'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'
import {
    CRMContact,
    CRMContactInsert,
    CRMContactUpdate,
    CRMDeal,
    CRMDealInsert,
    CRMDealUpdate,
    CRMDealWithContact
} from '@/types/crm'

export async function getContacts(userId?: string): Promise<CRMContact[]> {
    const supabase = await createClient()

    let query = supabase.from('crm_contacts').select('*')

    if (userId) {
        query = query.eq('user_id', userId)
    }

    const { data, error } = await query.order('full_name', { ascending: true }).limit(1000)

    if (error) {
        console.error('Error fetching contacts:', error)
        return []
    }

    return data as CRMContact[]
}

export async function getDeals(userId?: string, canViewAll = false): Promise<CRMDealWithContact[]> {
    const supabase = await createClient()

    let query = supabase
        .from('crm_deals')
        .select('*, contact:crm_contacts!crm_deals_contact_id_fkey(id, full_name, email, phone, company)')

    // If strict user filtering is needed and not viewing all
    if (userId && !canViewAll) {
        query = query.or(`user_id.eq.${userId},assigned_to.eq.${userId}`)
    }

    const { data, error } = await query.order('position', { ascending: true }).limit(500)

    if (error) {
        console.error('Error fetching deals:', error)
        return []
    }

    // Fetch profiles for owner and assignee
    const dealsData = data as any[]
    if (dealsData.length > 0) {
        const profileIds = [...new Set([...dealsData.map(d => d.user_id), ...dealsData.map(d => d.assigned_to)].filter(Boolean))]

        if (profileIds.length > 0) {
            const { data: profiles } = await supabase.from('profiles').select('id, full_name, email').in('id', profileIds)
            const profileMap = new Map((profiles || []).map((p: any) => [p.id, p]))

            return dealsData.map(deal => ({
                ...deal,
                owner_profile: profileMap.get(deal.user_id) || null,
                assigned_to_profile: profileMap.get(deal.assigned_to) || null
            }))
        }
    }

    return dealsData.map(deal => ({ ...deal, owner_profile: null, assigned_to_profile: null }))
}

export async function createContact(data: Omit<CRMContactInsert, 'user_id'>): Promise<CRMContact> {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) throw new Error('Unauthorized')

    const payload: CRMContactInsert = {
        ...data,
        user_id: user.id
    }

    const { data: result, error } = await supabase
        .from('crm_contacts')
        .insert(payload as never)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath('/crm')
    return result as CRMContact
}

