'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'
import {
    MedicalAppointment,
    MedicalAppointmentInsert,
    MedicalAppointmentUpdate,
    MedicalAppointmentWithRelations,
    GeneralMeeting
} from '@/types/agenda'

// --- Appointments ---

export async function getAppointments(filters: {
    startDate: Date
    endDate: Date
    doctorIds?: string[]
    patientId?: string
}): Promise<MedicalAppointmentWithRelations[]> {
    const supabase = await createClient()

    let query = supabase
        .from('medical_appointments')
        .select(`
      *,
      contact:crm_contacts(*),
      doctor:profiles!medical_appointments_doctor_id_fkey(id, full_name, email, role),
      financial_transaction:financial_transactions(id, description, amount, type)
    `)
        .gte('start_time', filters.startDate.toISOString())
        .lte('end_time', filters.endDate.toISOString())

    if (filters.doctorIds && filters.doctorIds.length > 0) {
        query = query.in('doctor_id', filters.doctorIds)
    }

    if (filters.patientId) {
        query = query.eq('contact_id', filters.patientId)
    }

    const { data, error } = await query

    if (error) {
        console.error('Error fetching appointments:', error)
        return []
    }

    return data as MedicalAppointmentWithRelations[]
}

export async function createAppointment(data: MedicalAppointmentInsert): Promise<MedicalAppointment> {
    const supabase = await createClient()

    const { data: result, error } = await supabase
        .from('medical_appointments')
        .insert(data as never)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath('/agenda')
    return result as MedicalAppointment
}

export async function updateAppointment(id: string, data: MedicalAppointmentUpdate): Promise<MedicalAppointment> {
    const supabase = await createClient()

    const { data: result, error } = await supabase
        .from('medical_appointments')
        .update(data as never)
        .eq('id', id)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath('/agenda')
    return result as MedicalAppointment
}

export async function deleteAppointment(id: string): Promise<void> {
    const supabase = await createClient()

    const { error } = await supabase
        .from('medical_appointments')
        .delete()
        .eq('id', id)

    if (error) throw new Error(error.message)

    revalidatePath('/agenda')
}

