// --- Availability ---

interface ConflictItem {
    id: string
    title: string
    start_time: string
    end_time: string
    type: 'appointment' | 'meeting'
}

export async function checkAvailability(
    startTime: Date,
    endTime: Date,
    excludeId?: string,
    doctorId?: string
): Promise<{ available: boolean; conflicts: ConflictItem[] }> {
    const supabase = await createClient()
    const startIso = startTime.toISOString()
    const endIso = endTime.toISOString()

    // Check appointments conflicts
    let appointmentsQuery = supabase
        .from('medical_appointments')
        .select('id, title, start_time, end_time')
        .or(`and(start_time.lt.${endIso},end_time.gt.${startIso})`)
        .neq('status', 'cancelled')

    if (excludeId) {
        appointmentsQuery = appointmentsQuery.neq('id', excludeId)
    }

    if (doctorId) {
        appointmentsQuery = appointmentsQuery.eq('doctor_id', doctorId)
    }

    const { data: appointmentsData } = await appointmentsQuery
    const appointments = appointmentsData as Array<{ id: string; title: string; start_time: string; end_time: string }> | null

    // Check meetings conflicts
    let meetingsQuery = supabase
        .from('general_meetings')
        .select('id, title, start_time, end_time')
        .or(`and(start_time.lt.${endIso},end_time.gt.${startIso})`)
        .eq('is_busy', true)
        .neq('status', 'cancelled')

    if (excludeId) {
        meetingsQuery = meetingsQuery.neq('id', excludeId)
    }

    if (doctorId) {
        meetingsQuery = meetingsQuery.eq('user_id', doctorId)
    }

    const { data: meetingsData } = await meetingsQuery
    const meetings = meetingsData as Array<{ id: string; title: string; start_time: string; end_time: string }> | null

    const conflicts: ConflictItem[] = [
        ...(appointments || []).map(a => ({
            id: a.id,
            title: a.title,
            start_time: a.start_time,
            end_time: a.end_time,
            type: 'appointment' as const
        })),
        ...(meetings || []).map(m => ({
            id: m.id,
            title: m.title,
            start_time: m.start_time,
            end_time: m.end_time,
            type: 'meeting' as const
        }))
    ]

    return {
        available: conflicts.length === 0,
        conflicts
    }
}
